/*
Inbound (from webhook) is optional:
{
  userId?: string,
  startDate?: 'YYYY-MM-DD',
  days?: number,
  demand?: [{ name, qty, unit, needBy? }],
  inventory?: { [name]: { qty, unit, min?, reorderTo? } } | [{ name, qty, unit, ... }],
  vendors?: [...],
  budget?: { weekly?, hardCap? },
  preferVendors?: [id]
}
*/
const b = items[0]?.json || {};
const apiBase = $env.SUKA_API_BASE || 'http://localhost:4000';

function toMapInventory(inv){
  if (!inv) return {};
  if (Array.isArray(inv)) {
    const m = {};
    for (const it of inv) m[String(it.name || '').toLowerCase()] = { qty: Number(it.qty||0), unit: it.unit || '', min: it.min, reorderTo: it.reorderTo };
    return m;
  }
  return inv;
}

const startDate = b.startDate || new Date().toISOString().slice(0,10);
const days = Math.max(1, Math.min(60, Number(b.days || 7)));
const userId = b.userId || null;

return [{ json: {
  apiBase,
  userId,
  startDate,
  days,
  budget: b.budget || { weekly: Number(b.budgetWeekly || 0) || undefined },
  preferVendors: Array.isArray(b.preferVendors) ? b.preferVendors : [],
  demandIn: Array.isArray(b.demand) ? b.demand : null,
  inventoryIn: toMapInventory(b.inventory) || null,
  vendorsIn: Array.isArray(b.vendors) ? b.vendors : null
} }];

/* Merge provided + fetched data into one planning request */
function arr(x){ return Array.isArray(x) ? x : []; }
function toInvMap(obj){
  if (!obj) return {};
  if (Array.isArray(obj)) { const m = {}; obj.forEach(o => m[String(o.name||'').toLowerCase()] = { qty: Number(o.qty||0), unit: o.unit||'' }); return m; }
  return obj;
}

const ctx = $json;
const demandFetched = $items('HTTP: Get Grocery List', 0, 0)[0]?.json || [];
const invFetched = $items('HTTP: Get Inventory', 0, 0)[0]?.json || {};
const vendorsFetched = $items('HTTP: Get Vendors/Catalog', 0, 0)[0]?.json || [];

const demand = ctx.demandIn || arr(demandFetched);
const inventory = ctx.inventoryIn || toInvMap(invFetched);
const vendors = ctx.vendorsIn || arr(vendorsFetched);

return [{ json: { ...ctx, demand, inventory, vendors } }];

/* If server plan succeeded, pass it through; else build a minimal fallback plan */
function ok(resp){ return resp && (resp.statusCode ? (resp.statusCode>=200 && resp.statusCode<300) : true); }
const apiPlan = $items('HTTP: Plan Procurement (server)', 0, 0)[0]?.json;
const apiOk = ok($items('HTTP: Plan Procurement (server)', 0, 0)[0]);

if (apiOk && apiPlan && Array.isArray(apiPlan.purchaseOrders) && apiPlan.purchaseOrders.length) {
  return [{ json: { plan: apiPlan, used: 'server' } }];
}

// ---- Fallback planner (very simple) ----
const ctx = $json;
const demand = Array.isArray(ctx.demand) ? ctx.demand : [];
const inv = ctx.inventory || {};

// 1) Aggregate demand by name
const map = new Map();
for (const d of demand) {
  const key = String(d.name||'').toLowerCase();
  const cur = map.get(key) || { name: d.name, unit: d.unit || '', qty: 0 };
  cur.qty += Number(d.qty || 0);
  map.set(key, cur);
}
// 2) Subtract simple inventory
for (const [k, v] of Object.entries(inv || {})) {
  const rec = map.get(k);
  if (!rec) continue;
  const onHand = Number(v.qty || 0);
  rec.qty = Math.max(0, rec.qty - onHand);
}
const needs = [...map.values()].filter(x => x.qty > 0);

// 3) Create one PO per (fake) vendor bucket (all to Local Grocer)
const orderDate = new Date();
const delivery = new Date(Date.now() + 2*24*3600*1000);
const po = {
  id: `po_${Date.now()}`,
  vendorId: 'local_grocer',
  vendorName: 'Local Grocer',
  orderDate: orderDate.toISOString(),
  estDeliveryDate: delivery.toISOString(),
  items: needs.map(n => ({ sku: null, name: n.name, qty: n.qty, unit: n.unit || '', packQty: 1, packs: 1, unitPrice: 0, extPrice: 0, needBy: ctx.startDate })),
  shipping: 0,
  subtotal: 0,
  total: 0
};

const plan = { purchaseOrders: needs.length ? [po] : [], backorders: [], substitutions: [], tasks: [], summary: { spend: 0, items: needs.length, vendors: needs.length ? 1 : 0, weekBuckets: [] } };
return [{ json: { plan, used: 'fallback' } }];

/* Convert POs to concrete tasks (place order + receive) */
const ctx = $items('Function: Merge Inputs', 0, 0)[0].json;
const plan = $json.plan || {};
const pos = Array.isArray(plan.purchaseOrders) ? plan.purchaseOrders : [];
const tasks = [];
for (const po of pos) {
  tasks.push({
    title: `Place order: ${po.vendorName}`,
    category: 'procurement',
    labels: ['purchase','auto-refill', po.vendorId || 'vendor'],
    priority: 2,
    due: po.orderDate,
    meta: { vendorId: po.vendorId, poId: po.id, items: po.items }
  });
  tasks.push({
    title: `Receive & stock: ${po.vendorName}`,
    category: 'inventory',
    labels: ['receiving','auto-refill', po.vendorId || 'vendor'],
    priority: 2,
    due: po.estDeliveryDate,
    meta: { vendorId: po.vendorId, poId: po.id, items: po.items }
  });
}
return tasks.length ? tasks.map(t => ({ json: { ...t, userId: ctx.userId, apiBase: ctx.apiBase } })) : [{ json: { skip: true, apiBase: ctx.apiBase } }];

/* Build a compact response summary for webhook or logs */
const used = ($items('Function: Use Server Plan or Fallback', 0, 0)[0]?.json?.used) || 'unknown';
const plan = ($items('Function: Use Server Plan or Fallback', 0, 0)[0]?.json?.plan) || { summary: {} };
const created = ($items('HTTP: Create Task', 0, 0) || []).length;
return [{ json: { ok: true, planner: used, purchaseOrders: (plan.purchaseOrders||[]).length, tasksCreated: created, summary: plan.summary || {} } }];
